// Simular procesamiento
const data = items[0].json;

// Crear mensaje simulado
const message = `💰 División de Factura\n\nTotal: $${data.totalAmount}\nPor persona: $${data.amountPerPerson}\n\n🏦 Banco: ${data.bankInfo.bankName}\nCuenta: ${data.bankInfo.accountNumber}\nTitular: ${data.bankInfo.accountHolder}`;

// Simular respuesta exitosa
let sentTo = [];

if (data.sendType === 'individual' && data.contacts) {
  sentTo = data.contacts.map(c => c.phone);
} else if (data.sendType === 'group' && data.group) {
  sentTo = [data.group.name];
}

return [{
  json: {
    success: true,
    message: "Envío simulado exitosamente (WhatsApp pendiente de aprobación)",
    sentTo: sentTo,
    simulatedMessage: message,
    receivedData: data
  }
}];
